// src/lib/practices.js
// ─────────────────────────────────────────────────────────────────────────────
// Held micro-practice library — static content, AI-surfaced.
//
// All practices are Manu's methodology: somatic, attachment-informed,
// nervous-system-first. Nothing is generated by AI — selection is.
//
// Structure:
//   PRACTICES        — full library, tagged by category + surface
//   getPractice()    — deterministic daily selector (by surface + date + state)
//   getLogPractice() — reactive selector triggered by what was just logged
//
// Surfaces:
//   "morning"    — Before 10am, body-first grounding
//   "invitation" — 10am–8pm, observational / curious
//   "evening"    — After 8pm, slowing down / closing the loop
//   "log_hard"   — After logging something difficult
//   "log_good"   — After logging a win or positive moment
//
// NS States (from regulation_checkins):
//   "overwhelmed" | "activated" | "shutdown" | "regulated" | null
// ─────────────────────────────────────────────────────────────────────────────

