// ─── NOTICED STATEMENTS ───────────────────────────────────────────────────────
// Held's observations — shown in the daily moment card below the streak bar.
// Rotate by day-of-week. Generated from real data in the app — these are
// templates; the actual numbers/words are filled in at render time.
// When no data exists yet, fall back to NOTICED_DEFAULT.

export const NOTICED_TEMPLATES = {
  // progress: fewer hard check-ins
  progress: (fewer, total) =>
    `You've felt overwhelmed less this week — ${fewer} check-in${fewer !== 1 ? "s" : ""} instead of ${total}. That's real movement, even if it doesn't feel like it yet.`,
  // consistency: they've been logging
  consistency: (days) =>
    `${days} days showing up. Most parents don't make it past three. Whatever's keeping you here — keep doing it.`,
  // pattern: something keeps coming up
  pattern: (topic, count) =>
    `${topic} keeps coming up for you — ${count} of your recent check-ins mention it. Your nervous system is paying attention.`,
  // hard_week: more rough nights than last
  hard_week: () =>
    `It's been a harder week than last. Worth naming — not fixing, just noticing. You're still here.`,
  // win: fewer rough nights
  win: (lastWeek, thisWeek) =>
    `Last week you had ${lastWeek} hard night${lastWeek !== 1 ? "s" : ""}. This week, ${thisWeek}. You probably don't feel the difference yet — but it's there.`,
  // showing_up: emotional labor
  showing_up: (count) =>
    `You've checked in ${count} time${count !== 1 ? "s" : ""} this week. Every one of those was a moment you chose yourself over the chaos.`,
};

export const NOTICED_DEFAULT =
  "Showing up — even on the hard days — is the practice. You're doing it.";

// ─── SELECTORS ───────────────────────────────────────────────────────────────

/**
 * getPractice(surface, nsState, seed)
 * Returns a single practice object for the given surface.
 *
 * @param {"morning"|"invitation"|"evening"} surface
 * @param {string|null} nsState  — parent's current NS state from check-in history
 * @param {number} seed          — use new Date().getDate() for daily rotation
 * @returns {{ id, text, sub }}
 */
export function getPractice(surface, nsState, seed = new Date().getDate()) {
  const pools = {
    morning:    MORNING,
    invitation: INVITATION,
    evening:    EVENING,
  };

  const pool = pools[surface] || INVITATION;

  // If parent is overwhelmed/activated, weight toward grounding practices
  // (those starting with m0x or e1x). Simple: pick from first half of pool.
  if (nsState === "overwhelmed" || nsState === "activated") {
    const groundingPool = pool.slice(0, Math.ceil(pool.length / 2));
    return groundingPool[seed % groundingPool.length];
  }

  // Default: rotate by seed (day of month keeps it stable all day, changes daily)
  return pool[seed % pool.length];
}

/**
 * getLogPractice(logType, isPositive, seed)
 * Returns a practice triggered by a specific log event.
 *
 * @param {"rough_night"|"short_nap"|"wont_settle"|"general_hard"} logType
 * @param {boolean} isPositive  — true for good log events
 * @param {number} seed
 * @returns {{ id, text, sub } | { id, notice, body, reflect, identity, anchor }}
 */
export function getLogPractice(logType, isPositive, seed = new Date().getDate()) {
  if (isPositive) {
    return LOG_GOOD[seed % LOG_GOOD.length];
  }

  const pool = LOG_HARD[logType] || LOG_HARD.general_hard;
  return pool[seed % pool.length];
}

/**
 * getNoticedStatement(patterns, familyState)
 * Returns the right "Held noticed" sentence based on real data.
 * Falls back to NOTICED_DEFAULT if no meaningful pattern exists.
 *
 * @param {object} patterns     — from useCheckinHistory()
 * @param {object} familyState  — from useFamilyState()
 * @param {number} seed         — day-of-week for rotation (0–6)
 * @returns {string}
 */
export function getNoticedStatement(patterns, familyState, seed = new Date().getDay()) {
  if (!patterns || patterns.total < 3) return NOTICED_DEFAULT;

  const options = [];

  // Progress: fewer hard check-ins this week vs last
  if (patterns.progressDelta !== null && patterns.progressDelta < -1) {
    options.push({
      type: "progress",
      text: NOTICED_TEMPLATES.progress(
        Math.abs(patterns.progressDelta),
        (patterns.total || 5)
      ),
    });
  }

  // Consistency: days showing up
  if (familyState?.daysShowingUp >= 5) {
    options.push({
      type: "consistency",
      text: NOTICED_TEMPLATES.consistency(familyState.daysShowingUp),
    });
  }

  // Pattern: hardest time keeps recurring
  if (patterns.hardestTime && patterns.hardestTimeCount >= 3) {
    options.push({
      type: "pattern",
      text: NOTICED_TEMPLATES.pattern(patterns.hardestTime, patterns.hardestTimeCount),
    });
  }

  // Hard week: more rough nights
  if (familyState?.sleepData?.consecutiveBadNights >= 3) {
    options.push({ type: "hard_week", text: NOTICED_TEMPLATES.hard_week() });
  }

  // Win: fewer rough nights this week vs last
  if (
    familyState?.sleepData?.lastWeekBadNights > 2 &&
    familyState?.sleepData?.thisWeekBadNights < familyState?.sleepData?.lastWeekBadNights
  ) {
    options.push({
      type: "win",
      text: NOTICED_TEMPLATES.win(
        familyState.sleepData.lastWeekBadNights,
        familyState.sleepData.thisWeekBadNights
      ),
    });
  }

  // Showing up: check-in count this week
  if (patterns.total >= 4) {
    options.push({
      type: "showing_up",
      text: NOTICED_TEMPLATES.showing_up(patterns.total),
    });
  }

  if (options.length === 0) return NOTICED_DEFAULT;

  // Rotate through available options by day-of-week
  // so it genuinely changes day to day when multiple apply
  return options[seed % options.length].text;
}
